import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import axios from "axios";
import Api from "../api/Api";

function Admin() {
  const [users, setUsers] = useState([]);
  const [showRequests, setShowRequests] = useState(false);

  const [requests, setRequests] = useState([]);
  const [orderMap, setOrderMap] = useState({});
  const [isSorted, setIsSorted] = useState(false);

  // ================= USERS =================
  const fetchUsers = async () => {
    try {
      const res = await axios.get(Api.get_All_User);
      setUsers(res.data || []);
    } catch (err) {
      console.log(err);
    }
  };

  // ================= REQUESTS =================
const fetchRequests = async () => {
  try {
    const res = await axios.get(Api.get_All_Emg_Req);

    console.log("RAW RESPONSE:", res.data);

    const data =
      res.data?.data ||
      res.data?.requests ||
      res.data ||
      [];

    setRequests(Array.isArray(data) ? data : []);
  } catch (err) {
    console.log("FETCH ERROR:", err);
    setRequests([]);
  }
};
  useEffect(() => {
    fetchUsers();
  }, []);

  // ================= ASSIGN ORDER (LIVE UI UPDATE) =================
const handleAssignOrder = async (id) => {
  try {
    const order = orderMap[id];

    if (order === undefined || order === "") {
      return alert("Enter order first");
    }

    const numOrder = Number(order);

    // 🔥 UI UPDATE FIRST
    setRequests((prev) =>
      prev.map((req) =>
        req._id === id
          ? { ...req, scheduleOrder: numOrder }
          : req
      )
    );

    // 🔥 API CALL (CORRECT)
 const res = await axios.put(
      `${Api.update_Emg_Order}/${id}`,
      {
        scheduleOrder: numOrder,
      }
    );

    console.log("UPDATE RESPONSE:", res.data);

    setOrderMap({});
    setIsSorted(false);

  } catch (err) {
    console.log("ASSIGN ERROR:", err.response || err);
    alert("Assign failed");
  }
};

  // ================= UPDATE ORDER =================
  const handleUpdateAssign = async (id) => {
    try {
      const order = orderMap[id];

      if (!order && order !== 0) {
        return alert("Enter order first");
      }

      setRequests((prev) =>
        prev.map((req) =>
          req._id === id
            ? { ...req, scheduleOrder: Number(order) }
            : req
        )
      );

      await axios.put(
        `${Api.update_Emg_Order}/${id}`,
        {
          scheduleOrder: Number(order),
        }
      );

      setOrderMap({});
      setIsSorted(false);

    } catch (err) {
      console.log(err);
    }
  };

  // ================= FINAL SORT =================
const displayedRequests = isSorted
  ? [...requests].sort((a, b) => {
      return (a.scheduleOrder || 0) - (b.scheduleOrder || 0);
    })
  : requests;

return (
  <div className="min-h-screen bg-[#eef2ea] p-8">

    <div className="max-w-7xl mx-auto">

      {/* HEADER */}
     {/* HEADER */}
<div className="mb-8">

 <h1 className="flex items-center gap-3 text-5xl font-extrabold text-green-900">
  <img
    src="garbageVehicle.jpeg"
    alt="CleanTrack Logo"
    className="w-14 h-16 object-contain"
  />

  CleanTrack
</h1>

  <p className="text-gray-600 mt-3 text-lg">
    Smart Waste Management Control Center
  </p>

</div>

      {/* ACTIONS */}
      <div className="bg-white rounded-2xl shadow-sm border border-[#d6ddd2] p-6 mb-8">

        <div className="flex flex-wrap gap-4">

          <Link to="/send-otp">
            <button className="bg-green-900 hover:bg-green-800 text-white px-6 py-3 rounded-xl font-semibold">
              + Create User
            </button>
          </Link>

          <button
            onClick={() => {
              setShowRequests(!showRequests);
              fetchRequests();
            }}
            className="bg-green-700 hover:bg-green-600 text-white px-6 py-3 rounded-xl font-semibold"
          >
            View Requests
          </button>

          <button
            onClick={() => setIsSorted(true)}
            className="bg-emerald-600 hover:bg-emerald-500 text-white px-6 py-3 rounded-xl font-semibold"
          >
            Final Sort
          </button>

        </div>

      </div>

      {/* USERS */}
      <div className="bg-white rounded-2xl shadow-sm border border-[#d6ddd2] p-6 mb-8">

        <div className="flex justify-between items-center mb-6">

          <h2 className="text-2xl font-bold text-green-900">
            User Management
          </h2>

          <span className="bg-green-100 text-green-800 px-4 py-2 rounded-full text-sm font-semibold">
            {users.length} Users
          </span>

        </div>

        <div className="overflow-x-auto">

          <table className="w-full">

            <thead>
              <tr className="bg-green-900 text-white">
                <th className="p-4 text-left">Name</th>
                <th className="p-4 text-left">Mobile</th>
                <th className="p-4 text-left">Role</th>
              </tr>
            </thead>

            <tbody>
              {users.map((user) => (
                <tr
                  key={user._id}
                  className="border-b hover:bg-green-50 transition"
                >
                  <td className="p-4 font-medium">
                    {user.name}
                  </td>

                  <td className="p-4">
                    {user.mobile}
                  </td>

                  <td className="p-4">
                    <span className="bg-green-100 text-green-800 px-3 py-1 rounded-full text-sm font-medium">
                      {user.role}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>

          </table>

        </div>

      </div>

      {/* REQUESTS */}
      {showRequests && (
        <div>

          <div className="flex justify-between items-center mb-6">

            <div>
              <h2 className="text-3xl font-bold text-green-900">
                Active Requests
              </h2>

              <p className="text-gray-500 text-sm">
                Pickup Scheduling & Monitoring
              </p>
            </div>

            <div className="bg-white border border-[#d6ddd2] px-5 py-3 rounded-xl">
              <span className="font-semibold">
                Total Requests:
              </span>{" "}
              {displayedRequests.length}
            </div>

          </div>

          {displayedRequests.length === 0 ? (

            <div className="bg-white rounded-2xl shadow-sm border border-[#d6ddd2] p-10 text-center">
              No requests found
            </div>

          ) : (

            <div className="grid lg:grid-cols-2 xl:grid-cols-3 gap-6">

              {displayedRequests.map((req) => (

                <div
                  key={req._id}
                  className="bg-white rounded-2xl border border-[#d6ddd2] p-6 hover:shadow-lg transition"
                >

                  {/* TOP */}
                  <div className="flex justify-between items-start">

                    <div>

                      <p className="text-xs uppercase tracking-wider text-gray-500">
                        Request #{req._id.slice(-5)}
                      </p>

                      <h3 className="text-xl font-bold text-green-900 mt-1">
                        {req.location?.location}
                      </h3>

                    </div>

                    <span
                      className={`px-4 py-1 rounded-full text-sm font-semibold
                      ${
                        req.status === "Completed"
                          ? "bg-green-100 text-green-800"
                          : req.status === "Accepted"
                          ? "bg-blue-100 text-blue-700"
                          : req.status === "Pending"
                          ? "bg-yellow-100 text-yellow-700"
                          : "bg-gray-100 text-gray-700"
                      }`}
                    >
                      {req.status}
                    </span>

                  </div>

                  {/* INFO */}
                  <div className="mt-5 space-y-2">

                    <p>
                      <span className="font-semibold">
                        Priority:
                      </span>{" "}
                      {req.priority}
                    </p>

                    <p className="text-sm text-gray-500">
                      Created:
                    </p>

                    <p className="text-sm">
                      {new Date(req.createdAt).toLocaleString("en-IN", {
                        day: "2-digit",
                        month: "short",
                        year: "numeric",
                        hour: "2-digit",
                        minute: "2-digit",
                        hour12: true,
                      })}
                    </p>

                  </div>

                  {/* ORDER */}
                  <div className="bg-green-50 rounded-xl p-4 mt-5">

                    <p className="text-sm text-gray-600">
                      Schedule Order
                    </p>

                    <p className="text-2xl font-bold text-green-900">
                      #{req.scheduleOrder || 0}
                    </p>

                  </div>

                  {/* ASSIGN */}
                  <div className="flex gap-3 mt-5">

                    <input
                      type="number"
                      placeholder="Set order"
                      className="flex-1 border border-[#d6ddd2] rounded-xl p-3 focus:outline-none focus:ring-2 focus:ring-green-700"
                      value={orderMap[req._id] ?? ""}
                      onChange={(e) =>
                        setOrderMap({
                          ...orderMap,
                          [req._id]: e.target.value,
                        })
                      }
                    />

                    <button
                      onClick={() => handleAssignOrder(req._id)}
                      className="bg-green-900 hover:bg-green-800 text-white px-5 rounded-xl font-semibold"
                    >
                      Assign
                    </button>

                  </div>

                </div>

              ))}

            </div>

          )}

        </div>
      )}

    </div>

  </div>
);
}

export default Admin;
